+/// prepared statement). Triggers are included as single `CREATE TRIGGER ... END;` statements.
+#[must_use]
+pub fn schema_migrations() -> Vec<Migration> {
+    let mut migrations: Vec<Migration> = Vec::new();
+
+    for chunk in CREATE_TABLES_SQL.split(';') {
+        let stmt = chunk.trim();
